css:
.loader {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
   width: 70px;
   aspect-ratio: 1;
   background: var(--loader-color, #16a34a);
   clip-path: polygon(100.00% 50.00%,68.48% 57.65%,85.36% 85.36%,57.65% 68.48%,50.00% 100.00%,42.35% 68.48%,14.64% 85.36%,31.52% 57.65%,0.00% 50.00%,31.52% 42.35%,14.64% 14.64%,42.35% 31.52%,50.00% 0.00%,57.65% 31.52%,85.36% 14.64%,68.48% 42.35%);
   -webkit-mask: radial-gradient(circle 5px,#0000 90%,currentColor);
   animation: l2 1.5s infinite linear;
}
@keyframes l2 {
  100%{transform: rotate(1turn)}
}
